<h3>Teacher Quick Grading</h3>
<div class="card mb-3"><div class="card-body"><h5><?= e($submission['title'] ?? '') ?></h5><p><?= nl2br(e($submission['content'] ?? '')) ?></p></div></div>
<div class="card mb-3"><div class="card-body"><h5>Quick Summary for teacher</h5><?php $sum=json_decode($feedback['summary_json']??'{}', true) ?: []; foreach(['task','coh','lex','gra'] as $k): ?><p><?= strtoupper($k) ?> suggested: <strong><?= e((string)($sum[$k]['score_suggested'] ?? '-')) ?></strong> - <?= e($sum[$k]['rationale'] ?? '') ?></p><?php endforeach; ?><p>Templates: <button class="btn btn-sm btn-outline-secondary" onclick="ins('Clear thesis and better examples needed.')">Task</button> <button class="btn btn-sm btn-outline-secondary" onclick="ins('Use more cohesive devices and stronger topic sentences.')">Cohesion</button></p></div></div>
<form method="post" action="/teacher/review/<?= $submission['id'] ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="row g-2"><?php foreach(['score_task'=>'Task','score_coh'=>'Coh','score_lex'=>'Lex','score_gra'=>'Gra'] as $n=>$l): ?><div class="col"><label><?=$l?></label><input step="0.5" min="0" max="9" name="<?=$n?>" class="form-control" value="<?= e((string)($review[$n] ?? ($sum[strtolower(str_replace('score_','',$n))]['score_suggested'] ?? 5))) ?>"></div><?php endforeach; ?></div><div class="my-2"><textarea id="comments" name="comments" class="form-control" rows="5"><?= e($review['comments'] ?? '') ?></textarea></div><div class="form-check"><input class="form-check-input" type="checkbox" name="featured" <?= !empty($review['featured'])?'checked':'' ?>><label class="form-check-label">Featured essay</label></div><button class="btn btn-success mt-2">Mark as reviewed</button></form>
<script>function ins(t){const c=document.getElementById('comments');c.value=(c.value+' '+t).trim();}</script>
